std::string convertMdfToJson(const MdfFormat& mdf) {
    std::ostringstream json;
    json << std::fixed << std::setprecision(6);

    const MdfHeader& header = mdf.GetHeader();

    json << "{\n";

    // Header
    json << "  \"header\": {\n";
    json << "    \"version\": \"" << std::string(header.cId, 8) << "\",\n";
    json << "    \"meshCount\": " << header.nMeshCount << ",\n";
    json << "    \"animCount\": " << header.nAnimCount << ",\n";
    json << "    \"textureCount\": " << header.nTextureCount << ",\n";
    json << "    \"byteAlignment\": " << header.nByteAlignment << ",\n";
    json << "    \"totalDataSize\": " << header.nTotalDataSize << "\n";
    json << "  },\n";

    // Textures - use placeholder names since texture access is broken
    json << "  \"textures\": [";
    for (unsigned int i = 0; i < mdf.GetNumTextures(); i++) {
        if (i > 0) json << ", ";
        json << "\"texture_" << i << ".dds\"";
    }
    json << "],\n";

    // Animations
    json << "  \"animations\": [";
    for (unsigned int i = 0; i < mdf.GetNumAnimations(); i++) {
        if (i > 0) json << ",";
        const TMdfAnimation& anim = mdf.GetAnimation(i);
        json << "\n    {\n";
        json << "      \"meshId\": " << anim.hMeshId << ",\n";
        json << "      \"timelineCount\": " << anim.nNumTimelines << ",\n";
        json << "      \"duration\": " << anim.fTimeLength << ",\n";
        json << "      \"timelines\": [";

        if (anim.uTls.pTimeline) {
            for (int t = 0; t < anim.nNumTimelines; t++) {
                if (t > 0) json << ",";
                const TMdfTimeline& timeline = anim.uTls.pTimeline[t];
                json << "\n        {\n";
                json << "          \"keyframeCount\": " << timeline.nKeyFrames << ",\n";
                json << "          \"keyframes\": [";

                if (timeline.uKfs.pKeyframes) {
                    for (int k = 0; k < timeline.nKeyFrames; k++) {
                        if (k > 0) json << ",";
                        const TMdfKeyframe& kf = timeline.uKfs.pKeyframes[k];
                        json << "\n            {\n";
                        json << "              \"time\": " << kf.fKeyTime << ",\n";
                        json << "              \"translation\": [" << kf.vecTranslation.x << ", " << kf.vecTranslation.y << ", " << kf.vecTranslation.z << "],\n";
                        json << "              \"rotation\": [" << kf.qRotation.x << ", " << kf.qRotation.y << ", " << kf.qRotation.z << ", " << kf.qRotation.w << "],\n";
                        json << "              \"scale\": [" << kf.vecScale.x << ", " << kf.vecScale.y << ", " << kf.vecScale.z << "]\n";
                        json << "            }";
                    }
                }
                json << "\n          ]\n";
                json << "        }";
            }
        }
        json << "\n      ]\n";
        json << "    }";
    }
    json << "\n  ],\n";

    // Meshes
    json << "  \"meshes\": [";
    for (unsigned int i = 0; i < mdf.GetNumMeshes(); i++) {
        if (i > 0) json << ",";
        const TMdfMesh& mesh = mdf.GetMesh(i);
        json << "\n    {\n";
        json << "      \"vertexCount\": " << mesh.nNumVerts << ",\n";
        json << "      \"indexCount\": " << mesh.nNumIndices << ",\n";
        json << "      \"jointCount\": " << mesh.nNumJoints << ",\n";
        json << "      \"textureIndex\": " << mesh.hTexture << ",\n";

        bool isSkinned = (mesh.nNumJoints > 0);
        json << "      \"type\": \"" << (isSkinned ? "skinned" : "static") << "\",\n";

        // Vertices
        json << "      \"vertices\": [";
        if (isSkinned && mesh.uVtxs.pVertices) {
            TMdfVertSkn* skinnedVerts = (TMdfVertSkn*)mesh.uVtxs.pVertices;
            for (unsigned int v = 0; v < mesh.nNumVerts; v++) {
                if (v > 0) json << ",";
                const TMdfVertSkn& vert = skinnedVerts[v];
                json << "\n        {\n";
                json << "          \"position\": [" << vert.pos.x << ", " << vert.pos.y << ", " << vert.pos.z << "],\n";
                json << "          \"weights\": [" << vert.weights[0] << ", " << vert.weights[1] << ", " << vert.weights[2] << "],\n";
                json << "          \"bones\": [" << (int)vert.bones[0] << ", " << (int)vert.bones[1] << ", " << (int)vert.bones[2] << ", " << (int)vert.bones[3] << "],\n";
                json << "          \"normal\": [" << vert.normal.x << ", " << vert.normal.y << ", " << vert.normal.z << "],\n";
                json << "          \"texcoord\": [" << vert.texcoord.u << ", " << vert.texcoord.v << "]\n";
                json << "        }";
            }
        } else if (mesh.uVtxs.pVertices) {
            TMdfVertSta* staticVerts = (TMdfVertSta*)mesh.uVtxs.pVertices;
            for (unsigned int v = 0; v < mesh.nNumVerts; v++) {
                if (v > 0) json << ",";
                const TMdfVertSta& vert = staticVerts[v];
                json << "\n        {\n";
                json << "          \"position\": [" << vert.pos.x << ", " << vert.pos.y << ", " << vert.pos.z << "],\n";
                json << "          \"normal\": [" << vert.normal.x << ", " << vert.normal.y << ", " << vert.normal.z << "],\n";
                json << "          \"texcoord\": [" << vert.texcoord.u << ", " << vert.texcoord.v << "]\n";
                json << "        }";
            }
        }
        json << "\n      ],\n";

        // Indices
        json << "      \"indices\": [";
        if (mesh.uIdxs.pIndices) {
            for (unsigned int idx = 0; idx < mesh.nNumIndices; idx++) {
                if (idx > 0) json << ", ";
                json << mesh.uIdxs.pIndices[idx];
            }
        }
        json << "]";

        // Bind pose and parent info for skinned meshes
        if (isSkinned) {
            if (mesh.uBnd.pBindMats) {
                json << ",\n      \"bindPose\": [";
                for (unsigned int b = 0; b < mesh.nNumJoints; b++) {
                    if (b > 0) json << ",";
                    json << "\n        [";
                    for (int e = 0; e < 16; e++) {
                        if (e > 0) json << ", ";
                        json << mesh.uBnd.pBindMats[b].e[e];
                    }
                    json << "]";
                }
                json << "\n      ]";
            }

            if (mesh.uPrnt.pParentInfo) {
                json << ",\n      \"parentInfo\": [";
                for (unsigned int p = 0; p < mesh.nNumJoints; p++) {
                    if (p > 0) json << ", ";
                    json << mesh.uPrnt.pParentInfo[p];
                }
                json << "]";
            }
        }

        json << "\n    }";
    }
    json << "\n  ]\n";

    json << "}";
    return json.str();
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: " << argv[0] << " <input.mdf> <output.json>" << std::endl;
        return 1;
    }

    const char* inputFile = argv[1];
    const char* outputFile = argv[2];

    MdfFormat mdf;
    if (!mdf.CreateFromFile(inputFile)) {
        std::cerr << "Error: Failed to load MDF file: " << inputFile << std::endl;
        return 1;
    }

    std::string jsonOutput = convertMdfToJson(mdf);

    std::ofstream outFile(outputFile);
    if (!outFile.is_open()) {
        std::cerr << "Error: Failed to create output file: " << outputFile << std::endl;
        return 1;
    }

    outFile << jsonOutput << std::endl;
    outFile.close();

    std::cout << "Successfully converted " << inputFile << " to " << outputFile << std::endl;
    return 0;
}
EOF
