        json << "\"texture_" << i << ".dds\"";
    }
    json << "],\n";

    // Animations
    json << "  \"animations\": [";
    for (unsigned int i = 0; i < mdf.GetNumAnimations(); i++) {
        if (i > 0) json << ",";
        const TMdfAnimation& anim = mdf.GetAnimation(i);
        json << "\n    {\n";
        json << "      \"meshId\": " << anim.hMeshId << ",\n";
        json << "      \"timelineCount\": " << anim.nNumTimelines << ",\n";
        json << "      \"duration\": " << anim.fTimeLength << ",\n";
        json << "      \"timelines\": [";

        if (anim.uTls.pTimeline) {
            for (int t = 0; t < anim.nNumTimelines; t++) {
                if (t > 0) json << ",";
                const TMdfTimeline& timeline = anim.uTls.pTimeline[t];
                json << "\n        {\n";
                json << "          \"keyframeCount\": " << timeline.nKeyFrames << ",\n";
                json << "          \"keyframes\": [";

                if (timeline.uKfs.pKeyframes) {
