                }
            } else {
                TMdfVertSta* staticVerts = (TMdfVertSta*)mesh.uVtxs.pVertices;
                for (unsigned int v = 0; v < mesh.nNumVerts; v++) {
                    if (v > 0) json << ",";
                    const TMdfVertSta& vert = staticVerts[v];
                    json << "\n        {\n";
                    json << "          \"position\": [" << vert.pos.x << ", " << vert.pos.y << ", " << vert.pos.z << "],\n";
                    json << "          \"normal\": [" << vert.normal.x << ", " << vert.normal.y << ", " << vert.normal.z << "],\n";
                    json << "          \"texcoord\": [" << vert.texcoord.u << ", " << vert.texcoord.v << "]\n";
                    json << "        }";
                }
            }
        }
        json << "\n      ],\n";

        // Indices
        json << "      \"indices\": [";
        if (mesh.uIdxs.pIndices && mesh.nNumIndices > 0) {
            for (unsigned int idx = 0; idx < mesh.nNumIndices; idx++) {
                if (idx > 0) json << ", ";
                json << mesh.uIdxs.pIndices[idx];
            }
        }
        json << "]";

        // Bind pose and parent info for skinned meshes
        if (isSkinned) {
            if (mesh.uBnd.pBindMats) {
                json << ",\n      \"bindPose\": [";
                for (unsigned int b = 0; b < mesh.nNumJoints; b++) {
                    if (b > 0) json << ",";
                    json << "\n        [";
                    for (int e = 0; e < 16; e++) {
                        if (e > 0) json << ", ";
                        json << mesh.uBnd.pBindMats[b].e[e];
                    }
                    json << "]";
                }
                json << "\n      ]";
            }

            if (mesh.uPrnt.pParentInfo) {
                json << ",\n      \"parentInfo\": [";
                for (unsigned int p = 0; p < mesh.nNumJoints; p++) {
                    if (p > 0) json << ", ";
                    json << mesh.uPrnt.pParentInfo[p];
                }
                json << "]";
            }
        }

        json << "\n    }";
    }
    json << "\n  ]\n";

    json << "}";
    return json.str();
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: " << argv[0] << " <input.mdf> <output.json>" << std::endl;
        return 1;
    }

    const char* inputFile = argv[1];
    const char* outputFile = argv[2];

    std::cout << "Converting: " << inputFile << " -> " << outputFile << std::endl;

    MdfFormat mdf;
    if (!mdf.CreateFromFile(inputFile)) {
        std::cerr << "Error: Failed to load MDF file: " << inputFile << std::endl;
        return 1;
    }

    std::string jsonOutput = convertMdfToJson(mdf);

    std::ofstream outFile(outputFile);
    if (!outFile.is_open()) {
        std::cerr << "Error: Failed to create output file: " << outputFile << std::endl;
        return 1;
    }

    outFile << jsonOutput << std::endl;
    outFile.close();

    std::cout << "Successfully converted " << inputFile << " to " << outputFile << std::endl;
    return 0;
}
